### useSyncExternalStore

`useSyncExternalStore` lets you subscribe to an external store (like Redux, Zustand, or browser APIs) and get synchronous updates. It ensures consistency with React's concurrent features.

---

### Syntax

```jsx
import { useSyncExternalStore } from 'react';

const state = useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot?);
```

### Basic Example

```jsx
function useOnlineStatus() {
  const isOnline = useSyncExternalStore(
    (callback) => {
      window.addEventListener('online', callback);
      window.addEventListener('offline', callback);
      return () => {
        window.removeEventListener('online', callback);
        window.removeEventListener('offline', callback);
      };
    },
    () => navigator.onLine
  );
  return isOnline;
}

function StatusIndicator() {
  const isOnline = useOnlineStatus();
  return <div>{isOnline ? 'Online' : 'Offline'}</div>;
}
```

### Parameters

| Parameter | Purpose |
|-----------|---------|
| `subscribe` | Registers a callback to call when store changes |
| `getSnapshot` | Returns current value of the store |
| `getServerSnapshot` (optional) | Returns snapshot for SSR |

### External Store Subscription

```jsx
function useStore(store) {
  return useSyncExternalStore(
    store.subscribe,
    () => store.getState()
  );
}
```

> **Key Point:** useSyncExternalStore is the correct way to integrate external state management libraries with React 18+. It prevents tearing (inconsistent UI) during concurrent rendering. Libraries like Redux and Zustand use this internally.

codeExample:
import { useSyncExternalStore } from 'react';

const store = {
  state: { count: 0 },
  listeners: new Set(),
  subscribe(listener) {
    this.listeners.add(listener);
    return () => this.listeners.delete(listener);
  },
  getState() { return this.state; },
  setState(next) {
    this.state = typeof next === 'function' ? next(this.state) : next;
    this.listeners.forEach(l => l());
  }
};

function Counter() {
  const state = useSyncExternalStore(
    store.subscribe.bind(store),
    store.getState.bind(store)
  );
  return <button onClick={() => store.setState(s => ({ count: s.count + 1 }))}>{state.count}</button>;
}
